conditions.value_template:
{% set n = (states('sensor.sm_f766u_last_notification') or '') | lower %}
{% set t = (state_attr('sensor.sm_f766u_last_notification', 'android.title') or '') | lower %}
{% set combined = n ~ ' ' ~ t %}
{# EXCLUDE order confirmations - these say delivery is coming LATER #}
{% set is_confirmation = 'we\'ll send an alert' in combined or 'delivery order received' in t %}
{# REAL en-route notifications #}
{% set is_real_enroute = 
    'expect delivery around' in combined or 
    'your delivery is on the way' in combined or 
    'is set to arrive by' in combined or
    'delivery is set to arrive' in combined or
    ('will leave your' in combined and 'tap to track' in combined) %}
{{ is_real_enroute and not is_confirmation }}
